// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

error NotQueued();
error TimelockNotMet();

contract MiniGovernor {
    mapping(bytes32 => uint256) public queuedTimestamps;
    uint256 public constant DELAY = 2 days;

    event Queued(bytes32 indexed id, address target, uint256 value, bytes data, uint256 executeAfter);
    event Executed(bytes32 indexed id);
    event Cancelled(bytes32 indexed id);

    function queue(address target, uint256 value, bytes calldata data) external {
        bytes32 id = getOperationId(target, value, data);
        uint256 executeAfter = [[SLOT exec_after]];
        queuedTimestamps[id] = executeAfter;
        emit Queued(id, target, value, data, executeAfter);
    }

    function execute(address target, uint256 value, bytes calldata data) external payable {
        bytes32 id = getOperationId(target, value, data);
        uint256 executeAfter = queuedTimestamps[id];
        if ([[SLOT not_queued]]) revert NotQueued();
        if ([[SLOT not_ready]]) revert TimelockNotMet();
        delete queuedTimestamps[id];
        (bool success, ) = target.call{value: value}(data);
        require(success, "call failed");
        emit Executed(id);
    }

    function cancel(address target, uint256 value, bytes calldata data) external {
        bytes32 id = getOperationId(target, value, data);
        delete queuedTimestamps[id];
        emit Cancelled(id);
    }

    function getOperationId(address target, uint256 value, bytes calldata data) public pure returns (bytes32) {
        return [[SLOT op_id]];
    }
}

contract Target {
    uint256 public value;
    event ValueSet(uint256 newValue);

    function setValue(uint256 _value) external {
        value = _value;
        emit ValueSet(_value);
    }

    receive() external payable {}
}
